from datetime import datetime, timedelta


def supplier_risk_assessment(supplier_data: dict):
    """
    Assesses the risk associated with a supplier based on factors such as lead time, capacity, delivery performance, price stability, and contract terms. The function analyzes supplier data to identify potential risks and provides a detailed summary of the assessment.

    Args:
        supplier_data (dict): A dictionary containing the supplier's data, including supplier details, order history, price history, and contract details.

    Returns:
        str: A detailed summary of the risk assessment, including risk levels for lead time, capacity, delivery performance, price stability, and contract terms, along with explanations for each factor.
    """
    if not supplier_data:
        return {'error': 'Supplier data not found.'}
    supplier_id = supplier_data['supplier_id']
    supplier_name = supplier_data['supplier_name']
    supplier_lead_time = supplier_data['supplier_lead_time']
    supplier_capacity = supplier_data['supplier_capacity']
    order_history = supplier_data['order_history']
    price_history = supplier_data['price_history']
    contract_details = supplier_data['contract_details']
    risk_factors = {}
    analysis_summary = []
    analysis_summary.append(f'Supplier ID: {supplier_id}')
    analysis_summary.append(f'Supplier Name: {supplier_name}')
    if supplier_lead_time > 30:
        lead_time_risk = 'High'
        lead_time_explanation = (
            f"The supplier's lead time of {supplier_lead_time} days exceeds 30 days, which could cause delays in receiving goods, impacting operations."
            )
    elif supplier_lead_time > 20:
        lead_time_risk = 'Medium'
        lead_time_explanation = (
            f"The supplier's lead time of {supplier_lead_time} days is between 20 and 30 days, which could cause some delays, but may still be manageable."
            )
    else:
        lead_time_risk = 'Low'
        lead_time_explanation = (
            f"The supplier's lead time of {supplier_lead_time} days is under 20 days, indicating timely deliveries and low risk of delays."
            )
    risk_factors['lead_time'] = lead_time_risk
    analysis_summary.append(
        f'Lead time risk: {lead_time_risk}. {lead_time_explanation}')
    if supplier_capacity < 1000:
        capacity_risk = 'High'
        capacity_explanation = (
            f"The supplier's capacity is {supplier_capacity} units, which is below 1000 units. This low capacity may cause them to struggle in fulfilling large or urgent orders."
            )
    elif supplier_capacity < 1500:
        capacity_risk = 'Medium'
        capacity_explanation = (
            f"The supplier's capacity of {supplier_capacity} units is moderate. While it may suffice for normal demand, they could face challenges during peak periods."
            )
    else:
        capacity_risk = 'Low'
        capacity_explanation = (
            f"The supplier's capacity of {supplier_capacity} units is high, meaning they can easily meet large orders and accommodate spikes in demand."
            )
    risk_factors['capacity'] = capacity_risk
    analysis_summary.append(
        f'Capacity risk: {capacity_risk}. {capacity_explanation}')
    on_time_deliveries = 0
    late_deliveries = 0
    cancelled_orders = 0
    for order in order_history:
        (order_id, product_id, quantity, order_date, delivery_date,
            order_status) = order
        if order_status == 'Delivered':
            order_date = datetime.strptime(order_date, '%Y-%m-%d').date()
            if delivery_date:
                delivery_date = datetime.strptime(delivery_date, '%Y-%m-%d'
                    ).date()
                expected_delivery_date = order_date + timedelta(days=
                    supplier_lead_time)
                if delivery_date <= expected_delivery_date:
                    on_time_deliveries += 1
                else:
                    late_deliveries += 1
        elif order_status == 'Cancelled':
            cancelled_orders += 1
    delivery_risk_level = 'Low'
    if late_deliveries > 3 or cancelled_orders > on_time_deliveries:
        delivery_risk_level = 'High'
        delivery_explanation = (
            f'High delivery risk due to {late_deliveries} late deliveries and {cancelled_orders} cancelled orders. This indicates issues in meeting delivery deadlines.'
            )
    elif late_deliveries > on_time_deliveries:
        delivery_risk_level = 'High'
        delivery_explanation = (
            f'High delivery risk because late deliveries ({late_deliveries}) outnumber on-time deliveries ({on_time_deliveries}), suggesting inconsistent performance.'
            )
    else:
        delivery_explanation = (
            'Delivery performance is within an acceptable range, with most orders delivered on time and no significant cancellations.'
            )
    risk_factors['delivery_performance'] = {'on_time_deliveries':
        on_time_deliveries, 'late_deliveries': late_deliveries,
        'cancelled_orders': cancelled_orders}
    risk_factors['delivery_risk_level'] = delivery_risk_level
    analysis_summary.append(
        f'Delivery details: On-time deliveries = {on_time_deliveries}, Late deliveries = {late_deliveries}, Cancelled orders = {cancelled_orders}.'
        )
    analysis_summary.append(
        f'Delivery risk: {delivery_risk_level}. {delivery_explanation}')
    product_price_risks = {}
    product_prices = {}
    for product_id, product_name, price, date in price_history:
        if product_id not in product_prices:
            product_prices[product_id] = {'name': product_name, 'prices': []}
        product_prices[product_id]['prices'].append(price)
    for product_id, product_data in product_prices.items():
        prices = product_data['prices']
        product_name = product_data['name']
        price_fluctuations = 0
        if len(prices) > 1:
            price_range = max(prices) - min(prices)
            average_price = sum(prices) / len(prices)
            if average_price > 0:
                price_fluctuations = price_range / average_price * 100
            else:
                price_fluctuations = 0
            if prices[-1] > prices[0]:
                price_trend = 'Increasing'
                price_trend_explanation = (
                    f'Prices for {product_name} are trending upwards, with the latest price of {prices[-1]} being higher than the first recorded price of {prices[0]}.'
                    )
            else:
                price_trend = 'Stable'
                price_trend_explanation = (
                    f'Prices for {product_name} have remained stable over time, indicating consistent pricing.'
                    )
            if price_fluctuations > 15:
                price_risk = 'High'
                price_risk_explanation = (
                    f'There is high volatility in pricing for {product_name}, with a fluctuation of {price_fluctuations:.2f}%, which could pose a risk to financial planning.'
                    )
            elif price_fluctuations > 5:
                price_risk = 'Medium'
                price_risk_explanation = (
                    f'Pricing for {product_name} fluctuates moderately by {price_fluctuations:.2f}%, which may impact budgeting but is still manageable.'
                    )
            else:
                price_risk = 'Low'
                price_risk_explanation = (
                    f'The price of {product_name} is relatively stable, with fluctuations below 5%, posing minimal risk.'
                    )
        else:
            price_risk = 'Low'
            price_trend = 'Unknown'
            price_risk_explanation = (
                f'Insufficient data for {product_name} to assess price fluctuations.'
                )
        product_price_risks[product_name] = {'risk': price_risk, 'trend':
            price_trend, 'explanation': price_risk_explanation}
    risk_factors['price'] = product_price_risks
    analysis_summary.append(f'Financial risk: {product_price_risks}.')
    contract_risk_level = 'Low'
    if contract_details:
        for contract in contract_details:
            (contract_id, product_id, description, pricing_terms,
                payment_terms, delivery_terms, expiration_date) = contract
            if pricing_terms == 'Variable':
                pricing_risk = 'High'
                pricing_explanation = (
                    f'The contract includes variable pricing terms, which could lead to unpredictable cost changes during the contract period.'
                    )
            elif pricing_terms == 'Tiered':
                pricing_risk = 'Medium'
                pricing_explanation = (
                    f'The contract includes tiered pricing terms, which may offer price reductions but could be subject to fluctuating volumes.'
                    )
            else:
                pricing_risk = 'Low'
                pricing_explanation = (
                    'The contract includes fixed pricing terms, ensuring predictable and stable costs.'
                    )
            if payment_terms == 'Net 30 days':
                payment_risk = 'High'
                payment_explanation = (
                    f"The payment terms are {payment_terms},  which is relatively short period, which may strain the buyer's cash flow."
                    )
            elif payment_terms == 'Net 90 days':
                payment_risk = 'Low'
                payment_explanation = (
                    f'The payment terms are {payment_terms}, which offers a longer window for the buyer to manage cash flow and make payments.'
                    )
            else:
                payment_risk = 'Medium'
                payment_explanation = (
                    f'The payment terms are {payment_terms}, which offers more flexibility but still requires careful cash flow management.'
                    )
            risk_factors[f'contract_{contract_id}_pricing'] = pricing_risk
            risk_factors[f'contract_{contract_id}_payment'] = payment_risk
            analysis_summary.append(
                f'Contract {contract_id} pricing risk: {pricing_risk}. {pricing_explanation}'
                )
            analysis_summary.append(
                f'Contract {contract_id} payment risk: {payment_risk}. {payment_explanation}'
                )
            if pricing_risk == 'High' or payment_risk == 'Medium':
                contract_risk_level = 'High'
            elif pricing_risk == 'Medium' or payment_risk == 'Medium':
                contract_risk_level = 'Medium'
    else:
        analysis_summary.append('No contract found for this supplier.')
    analysis_summary_text = '\n'.join(analysis_summary)
    return analysis_summary_text

import math


def inventory_optimization(inventory_data: dict):
    """
    Calculates the optimal inventory levels for a product using supplier-specific data to minimize ordering and holding costs. Computes the Economic Order Quantity (EOQ) and Reorder Point (ROP) for each supplier.

    Args:
        inventory_data (dict): A dictionary containing product and supplier-specific inventory and demand data. Includes product ID, supplier ID, annual demand, and inventory details such as quantity on hand, holding cost, ordering cost, and lead time.

    Returns:
        dict: A dictionary containing the product ID and inventory optimization results (EOQ and ROP) for each supplier. If no data is provided, returns a summary indicating the absence of product or supplier data.
    """
    if not inventory_data:
        return {'analysis_summary': 'No product data provided.'}
    inventory_optimization_data = {'product_id': inventory_data.get(
        'product_id', 'unknown')}
    suppliers_key = None
    if 'suppliers' in inventory_data:
        suppliers_key = 'suppliers'
    elif 'supplier_data' in inventory_data:
        suppliers_key = 'supplier_data'
    if not suppliers_key:
        return {'analysis_summary':
            'No supplier data found in the provided information.'}
    inventory_optimization_data['suppliers'] = {}
    for supplier_id, supplier_data in inventory_data[suppliers_key].items():
        quantity_on_hand = supplier_data['inventory']['quantity_on_hand']
        holding_cost = supplier_data['inventory']['holding_cost']
        ordering_cost = supplier_data['inventory']['ordering_cost']
        lead_time = supplier_data['inventory']['lead_time']
        annual_demand = supplier_data['annual_demand']
        eoq = math.sqrt(2 * annual_demand * ordering_cost / holding_cost
            ) if holding_cost != 0 else 0
        average_weekly_demand = annual_demand / 52
        reorder_point = average_weekly_demand * lead_time
        inventory_optimization_data['suppliers'][supplier_id] = {
            'quantity_on_hand': quantity_on_hand, 'annual_demand':
            annual_demand, 'holding_cost': holding_cost, 'ordering_cost':
            ordering_cost, 'lead_time': lead_time, 'EOQ': round(eoq, 2),
            'ROP': round(reorder_point, 2)}
    return inventory_optimization_data

import sqlite3


def contract_analysis(supplier_id: int, product_id: int):
    """
    Analyzes contract terms between a specific supplier and product, retrieving details such as pricing, payment terms, delivery schedule, warranty, liability, expiration date, and renewal terms. It also evaluates the overall risk level based on specific conditions in the contract.

    Args:
        supplier_id (int): The ID of the supplier whose contract is to be analyzed.
        product_id (int): The ID of the product whose contract is to be analyzed.

    Returns:
        str: A summary of the contract analysis, including contract terms, pricing terms, payment terms, delivery schedule, warranty, liability, expiration date, renewal terms, and an overall risk level assessment. If no contract exists, returns a message indicating the absence of a contract.
    """
    db_name = 'user_uploads/SupplyChain.db'
    with sqlite3.connect(db_name) as conn:
        cursor = conn.cursor()
        cursor.execute(
            """SELECT ContractTerms, PricingTerms, PaymentTerms, DeliverySchedule, 
                      Warranty, Liability, ExpirationDate, RenewalTerms 
               FROM Contracts 
               WHERE SupplierID = ? AND ProductID = ?"""
            , (supplier_id, product_id))
        contract_data = cursor.fetchone()
        if not contract_data:
            return (
                f'Product ID {product_id} does not have any contract with Supplier ID {supplier_id}.'
                )
        (contract_terms, pricing_terms, payment_terms, delivery_schedule,
            warranty, liability, expiration_date, renewal_terms
            ) = contract_data
        risk_level = 'Medium'
        if 'Variable' in pricing_terms or 'Net 30 days' in payment_terms:
            risk_level = 'High'
        elif 'Unlimited' in liability or 'Fixed' in pricing_terms:
            risk_level = 'Low'
        contract_analysis_summary = f"""Product ID: {product_id}, Supplier ID: {supplier_id}
Contract Terms: {contract_terms}
Pricing Terms: {pricing_terms}, Payment Terms: {payment_terms}
Delivery Schedule: {delivery_schedule}, Warranty: {warranty}, Liability: {liability}
Expiration Date: {expiration_date}, Renewal Terms: {renewal_terms}
Overall Risk Level: {risk_level}"""
    return contract_analysis_summary
